export const expansionQaItems: QAItem[] = [
  { id: 'expansion-qa-form-boundary', topicId: 'expansion-accessible-forms', topicFamily: 'app-quality', question: 'Why does a form need server-side validation if it already validates in the browser?', answer: 'Browser validation improves feedback, but a client can be bypassed. The server must parse and authorize input at the mutation boundary.', followUp: 'Which error should the user see after a rejected submission?', category: 'nextjs', level: 'intermediate', tags: ['expansion', 'forms', 'server-validation'], sourceLink: 'https://nextjs.org/docs/app/guides/forms' },
  { id: 'expansion-qa-runtime-schema', topicId: 'expansion-runtime-schema-boundaries', topicFamily: 'app-quality', question: 'Why use a runtime schema for FormData when the fields already have TypeScript types?', answer: 'TypeScript types guide compilation but do not inspect values submitted by a browser or another client. A runtime schema parses the input, returns structured issues on failure, and produces data the server can safely pass to the next boundary; authorization is still a separate check.', followUp: 'How should field issues become accessible recovery feedback?', category: 'nextjs', level: 'intermediate', tags: ['expansion', 'schemas', 'zod', 'forms', 'runtime-validation'], sourceLink: 'https://zod.dev/basics', sourceLinks: ['https://nextjs.org/docs/15/app/guides/forms'] },
  { id: 'expansion-qa-form-semantics', topicId: 'expansion-accessible-forms', topicFamily: 'app-quality', question: 'What is the strongest default for a form field label?', answer: 'Use a visible label associated with a native control. Placeholder text is not a durable replacement for a label.', followUp: 'How would you test the association?', category: 'accessibility', level: 'beginner', tags: ['expansion', 'forms', 'semantics'], sourceLink: 'https://www.w3.org/WAI/ARIA/apg/' },
  { id: 'expansion-qa-url-state', topicId: 'expansion-url-state', topicFamily: 'nextjs-data', question: 'When should a filter live in the URL?', answer: 'When users should be able to refresh, bookmark, navigate back to, or share that exact filtered view.', followUp: 'Which values should remain local instead?', category: 'nextjs', level: 'intermediate', tags: ['expansion', 'url-state', 'search-params'], sourceLink: 'https://nextjs.org/docs/15/app/getting-started/linking-and-navigating' },
  { id: 'expansion-qa-fetch-failure', topicId: 'expansion-browser-failure-debugging', topicFamily: 'app-quality', question: 'Why is response.ok needed after fetch() resolves?', answer: 'fetch() resolves when an HTTP response is received, including 404 or 500 responses. Check response.ok or status before treating the body as a successful result.', followUp: 'How should a stale response be handled?', category: 'debugging', level: 'intermediate', tags: ['expansion', 'fetch', 'debugging'], sourceLink: 'https://developer.mozilla.org/en-US/docs/Web/API/Fetch_API/Using_Fetch' },
  { id: 'expansion-qa-query-key', topicId: 'expansion-client-server-state', topicFamily: 'nextjs-data', question: 'What belongs in a TanStack Query query key?', answer: 'Every variable that changes the result belongs in the key, such as an owner id, filter, or page. The key lets the cache distinguish data variants and refetch the correct one.', followUp: 'What can go wrong when a result-changing variable is omitted?', category: 'nextjs', level: 'advanced', tags: ['expansion-client-server-state', 'query-cache', 'tanstack-query'], sourceLink: 'https://tanstack.com/query/latest/docs/framework/react/guides/query-keys' },
  { id: 'expansion-qa-query-invalidation', topicId: 'expansion-client-server-state', topicFamily: 'nextjs-data', question: 'Why should a mutation invalidate related queries?', answer: 'A successful write can make cached reads stale. Invalidation marks the affected query family for refresh so separate consumers do not keep presenting old server state.', followUp: 'When might a precise cache update be preferable to invalidation?', category: 'nextjs', level: 'advanced', tags: ['expansion-client-server-state', 'query-cache', 'mutations'], sourceLink: 'https://tanstack.com/query/latest/docs/framework/react/guides/invalidations-from-mutations' },
  { id: 'expansion-qa-profiler', topicId: 'expansion-performance-diagnosis', topicFamily: 'production', question: 'What does the React Profiler help you learn?', answer: 'It records render timing data for a component tree so you can investigate which interactions or components consume time. It does not by itself prove that memoization is the right fix.', followUp: 'Which other evidence would you collect for a slow initial page?', category: 'performance', level: 'advanced', tags: ['expansion-performance-diagnosis', 'profiling', 'rendering'], sourceLink: 'https://react.dev/reference/react/Profiler' },
  { id: 'expansion-qa-memoization', topicId: 'expansion-performance-diagnosis', topicFamily: 'production', question: 'Why is memoization an optimization rather than a correctness fix?', answer: 'memo and useMemo can skip or cache work when inputs are unchanged, but correctness still depends on pure rendering, complete props/dependencies, and the actual bottleneck. They add comparison or cache complexity and should be measured.', followUp: 'What can a memoized component still re-render for?', category: 'react', level: 'advanced', tags: ['expansion-performance-diagnosis', 'memo', 'useMemo'], sourceLink: 'https://react.dev/reference/react/memo', sourceLinks: ['https://react.dev/reference/react/useMemo'] },
  { id: 'expansion-qa-authz-boundary', topicId: 'expansion-authorization-boundaries', topicFamily: 'production', question: 'What is the difference between authentication and authorization?', answer: 'Authentication establishes who the caller is. Authorization decides whether that caller may perform a specific operation on a specific resource. Both must be enforced at the server boundary protecting the operation.', followUp: 'Why is hiding a button not authorization?', category: 'nextjs', level: 'advanced', tags: ['expansion-authorization-boundaries', 'authn', 'authz'], sourceLink: 'https://nextjs.org/docs/app/guides/authentication' },
  { id: 'expansion-qa-ownership-check', topicId: 'expansion-authorization-boundaries', topicFamily: 'production', question: 'How do you prevent an IDOR-style ownership bug?', answer: 'Do not trust an ownerId or role sent by the client. Derive identity from the authenticated server session and authorize the requested resource in the data operation or an equivalent server policy before returning or changing it.', followUp: 'Which direct request should be in the test?', category: 'architecture', level: 'advanced', tags: ['expansion-authorization-boundaries', 'ownership', 'security'], sourceLink: 'https://cheatsheetseries.owasp.org/cheatsheets/Authorization_Cheat_Sheet.html' },
  { id: 'expansion-qa-typescript-runtime', topicId: 'expansion-typescript-react-boundaries', topicFamily: 'foundations', question: 'Can a TypeScript interface validate API JSON at runtime?', answer: 'No. Interfaces and types guide compilation and are erased from runtime JavaScript. Parse or narrow the unknown value at the boundary before using it as the expected shape.', followUp: 'Where should an invalid payload become a user-visible error?', category: 'react', level: 'intermediate', tags: ['expansion-typescript-react-boundaries', 'typescript', 'runtime-validation'], sourceLink: 'https://www.typescriptlang.org/docs/handbook/2/narrowing.html' },
  { id: 'expansion-qa-typescript-union', topicId: 'expansion-typescript-react-boundaries', topicFamily: 'foundations', question: 'Why model loading, success, and failure as a union?', answer: 'A discriminated union makes the allowed states and required fields explicit, so rendering code must handle each state instead of reading success data from an error or loading branch.', followUp: 'What should be the discriminant field?', category: 'react', level: 'intermediate', tags: ['expansion-typescript-react-boundaries', 'unions', 'ui-state'], sourceLink: 'https://www.typescriptlang.org/docs/handbook/2/everyday-types.html' },
  { id: 'expansion-qa-testing-query', topicId: 'expansion-testing-user-behavior', topicFamily: 'app-quality', question: 'Why prefer role and label queries in component tests?', answer: 'They exercise the accessible, user-facing contract and fail when the UI becomes unusable, while private state and implementation names can change during a safe refactor.', followUp: 'When is a test id justified?', category: 'testing', level: 'intermediate', tags: ['expansion-testing-user-behavior', 'testing-library', 'accessibility'], sourceLink: 'https://testing-library.com/docs/queries/about/' },
  { id: 'expansion-qa-testing-layers', topicId: 'expansion-testing-user-behavior', topicFamily: 'app-quality', question: 'How should unit, component, and end-to-end tests divide responsibility?', answer: 'Use unit tests for pure logic, component tests for rendered interaction and state transitions, and end-to-end tests for a small set of critical cross-boundary journeys. Let product risk and integration cost guide the mix.', followUp: 'Which layer should cover a server rejection rendered in a form?', category: 'testing', level: 'intermediate', tags: ['expansion-testing-user-behavior', 'testing-layers', 'vitest', 'playwright'], sourceLink: 'https://testing-library.com/docs/react-testing-library/intro/', sourceLinks: ['https://playwright.dev/docs/intro'] },
  { id: 'expansion-qa-production-build', topicId: 'expansion-production-readiness', topicFamily: 'production', question: 'Why should a Next.js app be tested from a production-like build?', answer: 'Development and production can differ in bundling, environment loading, caching, server behavior, and failure handling. A production-like build and smoke flow expose those boundaries earlier.', followUp: 'Which route and failure should be part of the smoke flow?', category: 'nextjs', level: 'advanced', tags: ['expansion-production-readiness', 'build', 'deployment'], sourceLink: 'https://nextjs.org/docs/15/app/guides/production-checklist' },
  { id: 'expansion-qa-runtime-configuration', topicId: 'expansion-production-readiness', topicFamily: 'production', question: 'What makes an environment variable safe for the browser?', answer: 'Only values intentionally public should cross into browser code. Secrets and internal service configuration must remain server-only and be read at a protected server boundary.', followUp: 'How should a missing required server variable fail?', category: 'nextjs', level: 'advanced', tags: ['expansion-production-readiness', 'environment', 'security'], sourceLink: 'https://nextjs.org/docs/15/app/guides/production-checklist' },
  { id: 'expansion-qa-tool-ownership', topicId: 'expansion-ecosystem-comparisons', topicFamily: 'architecture', question: 'How should you decide whether to add Redux or another client store?', answer: 'First identify shared client-owned state that existing local, URL, or server-state boundaries do not serve well. Add a store only when its distinct ownership, benefits, and migration cost are explicit.', followUp: 'Why is a growing app alone not enough evidence?', category: 'architecture', level: 'advanced', tags: ['expansion-ecosystem-comparisons', 'redux', 'state-ownership'], sourceLink: 'https://redux-toolkit.js.org/introduction/getting-started' },
  { id: 'expansion-qa-next-router-choice', topicId: 'expansion-ecosystem-comparisons', topicFamily: 'architecture', question: 'Why can adding React Router beside Next App Router be risky?', answer: 'It can create competing route identity, data-loading models, navigation semantics, and ownership of URLs. A second router needs a concrete boundary and an explicit integration contract.', followUp: 'What separate requirement might justify it?', category: 'nextjs', level: 'advanced', tags: ['expansion-ecosystem-comparisons', 'react-router', 'next-app-router'], sourceLink: 'https://nextjs.org/docs/app' },
  { id: 'expansion-qa-optimistic-recovery', topicId: 'expansion-optimistic-mutations', topicFamily: 'nextjs-data', question: 'What makes an optimistic mutation trustworthy?', answer: 'The UI distinguishes a pending projection from confirmed server state, the mutation validates and authorizes at the server boundary, and rejection reconciles the projection with a visible retryable error.', followUp: 'Which value should replace a temporary client id after success?', category: 'nextjs', level: 'advanced', tags: ['expansion-optimistic-mutations', 'optimistic-ui', 'mutations', 'recovery'], sourceLink: 'https://react.dev/reference/react/useOptimistic', sourceLinks: ['https://nextjs.org/docs/app/guides/forms'] },
  { id: 'expansion-qa-route-recovery', topicId: 'app-router-and-layouts', topicFamily: 'nextjs-foundations', question: 'How should a Next.js App Router flow separate missing, expected, uncaught, and slow states?', answer: 'Use notFound for an expected missing resource, return deliberate validation or action feedback for expected failures, place error.tsx where it can catch uncaught render failures and offer reset, and use loading.tsx or nested Suspense for slow work. Event-handler failures still need their own handling.', followUp: 'Why is a single page-wide spinner a poor model for a slow nested dependency?', category: 'nextjs', level: 'advanced', tags: ['expansion-route-recovery', 'route-recovery', 'not-found', 'error-boundary', 'streaming'], sourceLink: 'https://nextjs.org/docs/15/app/getting-started/error-handling', sourceLinks: ['https://nextjs.org/docs/15/app/getting-started/fetching-data'] },
  { id: 'expansion-qa-instrumentation-triage', topicId: 'expansion-instrumentation-incident-triage', topicFamily: 'production', question: 'What does Next.js instrumentation contribute to an incident response?', answer: 'It provides a server-side integration seam such as register or onRequestError for collecting bounded request and error signals. It does not configure a vendor, prove the root cause, or justify logging secrets and unnecessary personal data.', followUp: 'Which evidence connects a browser-visible failure to a production hypothesis?', category: 'nextjs', level: 'advanced', tags: ['instrumentation', 'incident-response', 'observability', 'production'], sourceLink: 'https://nextjs.org/docs/15/app/guides/instrumentation', sourceLinks: ['https://nextjs.org/docs/15/app/api-reference/file-conventions/instrumentation'] },
  { id: 'expansion-qa-session-refresh-race', topicId: 'expansion-authorization-boundaries', topicFamily: 'production', question: 'How do you keep concurrent session refresh and logout bounded?', answer: 'Use one refresh owner or single-flight contract, cap retries, reject stale results after logout, and coordinate safe session-view invalidation across same-origin tabs. BroadcastChannel coordinates tabs but never replaces server authentication or authorization.', followUp: 'Which test proves a late refresh cannot resurrect a logged-out session?', category: 'architecture', level: 'expert', tags: ['expansion-authorization-boundaries', 'session', 'refresh-race', 'single-flight', 'security'], sourceLink: 'https://cheatsheetseries.owasp.org/cheatsheets/Session_Management_Cheat_Sheet.html', sourceLinks: ['https://developer.mozilla.org/en-US/docs/Web/API/BroadcastChannel', 'https://nextjs.org/docs/app/guides/authentication'] },
  ];

export const expansionPractices: BestPractice[] = [
  { id: 'expansion-validate-at-server-boundary', topicId: 'expansion-accessible-forms', topicFamily: 'app-quality', title: 'Validate Again at the Server Boundary', summary: 'Use client validation for fast feedback, but parse and authorize data again where the mutation is protected.', rationale: 'Clients are untrusted and can submit requests without rendering your form. The server boundary owns correctness and permission checks.', tradeOffs: 'The same rule may appear in client and server code; shared schemas can reduce drift when the runtime supports them.', appliesWhen: 'A form, action, or route handler changes protected data.', doesNotApplyWhen: 'The value never leaves the current process or affects a protected operation.', example: 'A signup form checks email format in the browser, then the Server Action parses it before creating the account.', sourceLink: 'https://nextjs.org/docs/app/guides/forms', nextVersion: 'Next.js 15.5.20', tags: ['expansion', 'forms', 'security'] },
  { id: 'expansion-parse-at-runtime-boundary', topicId: 'expansion-runtime-schema-boundaries', topicFamily: 'app-quality', title: 'Parse External Data Before Trusting It', summary: 'Use a runtime schema for FormData or JSON before passing values to a typed component, query, or mutation.', rationale: 'Compile-time types do not inspect runtime input. Parsing creates a deliberate success or recovery path and keeps invalid data from becoming an accidental application assumption.', tradeOffs: 'Schema definitions and field mapping add maintenance cost; keep them at real trust boundaries and avoid duplicating checks for purely internal values.', appliesWhen: 'Data comes from a browser form, API, URL, storage, or another untyped client.', doesNotApplyWhen: 'The value was constructed and validated inside the same trusted module.', example: 'Call `safeParse` at the Server Action boundary, return field issues on failure, then authorize and save only the parsed data.', sourceLink: 'https://zod.dev/basics', sourceLinks: ['https://nextjs.org/docs/15/app/guides/forms'], tags: ['expansion', 'schemas', 'zod', 'runtime-validation'] },
  { id: 'expansion-keep-shareable-state-in-url', topicId: 'expansion-url-state', topicFamily: 'nextjs-data', title: 'Keep Shareable Filters in the URL', summary: 'Represent filters, sorting, and pagination in search params when users need links, refreshes, or browser history.', rationale: 'A single URL owner makes the view reproducible and avoids synchronization drift between route state and a client store.', tradeOffs: 'URL keys become a public contract and need stable defaults, parsing, and reset rules.', appliesWhen: 'The state describes a view users may revisit or share.', doesNotApplyWhen: 'The value is transient interaction state such as an open menu or draft text.', example: 'Use `?query=react&page=2` for a catalog view; keep the filter popover’s open state local.', sourceLink: 'https://nextjs.org/docs/15/app/getting-started/linking-and-navigating', nextVersion: 'Next.js 15.5.20', tags: ['expansion', 'url-state', 'navigation'] },
  { id: 'expansion-ignore-obsolete-responses', topicId: 'expansion-browser-failure-debugging', topicFamily: 'app-quality', title: 'Keep Obsolete Responses from Winning', summary: 'When inputs change during an async request, abort or ignore responses that no longer match the current input.', rationale: 'Network completion order is independent from input order; rendering every response can show data for a query the user has already replaced.', tradeOffs: 'Cancellation needs cleanup, and ignored work may still consume server resources when cancellation is not supported.', appliesWhen: 'Search, autocomplete, filters, or any request is keyed by changing input.', doesNotApplyWhen: 'Every response is independently useful and can be appended without replacing current state.', example: 'Abort the previous search request on cleanup and ignore AbortError while preserving a retryable error state for other failures.', sourceLink: 'https://developer.mozilla.org/en-US/docs/Web/API/AbortController', tags: ['expansion', 'async', 'debugging'] },
  { id: 'expansion-keep-server-state-in-cache', topicId: 'expansion-client-server-state', topicFamily: 'nextjs-data', title: 'Keep Server State in a Query Cache', summary: 'Let a server-state cache own remote data, freshness, loading, and error transitions instead of mirroring the response into unrelated local state.', rationale: 'Remote data has identity and freshness rules. A dedicated cache can coordinate consumers and expose invalidation semantics without hand-written synchronization effects.', tradeOffs: 'A cache library adds concepts and configuration. Use it where shared remote data, retries, or invalidation justify the boundary; keep simple one-off reads simple.', appliesWhen: 'Several components consume the same remote data or mutations must refresh related reads.', doesNotApplyWhen: 'The value is purely local UI state or a simple server render with no client cache requirement.', example: 'Use a query key containing project owner and page, then invalidate the project query family after a successful edit.', sourceLink: 'https://tanstack.com/query/latest/docs/framework/react/overview', sourceLinks: ['https://tanstack.com/query/latest/docs/framework/react/guides/invalidations-from-mutations'], tags: ['expansion-client-server-state', 'query-cache', 'server-state'] },
  { id: 'expansion-measure-before-memo', topicId: 'expansion-performance-diagnosis', topicFamily: 'production', title: 'Measure Before Adding Memoization', summary: 'Profile a user-visible interaction and identify its dominant cost before adding memo or useMemo.', rationale: 'Memoization only addresses certain render or calculation costs. A baseline prevents optimizing the wrong layer and gives the team a result to compare.', tradeOffs: 'Profiling takes time and can reveal multiple contributors. That is cheaper than carrying memoization boundaries that obscure data flow without improving the measured interaction.', appliesWhen: 'A render or interaction is slow enough to affect users and the cause is not yet proven.', doesNotApplyWhen: 'There is no measured symptom or the bottleneck is clearly outside render work.', example: 'Record filter latency, profile the list, then memoize the measured row boundary only if stable props make the comparison useful.', sourceLink: 'https://react.dev/reference/react/Profiler', sourceLinks: ['https://react.dev/reference/react/memo', 'https://react.dev/reference/react/useMemo', 'https://nextjs.org/docs/15/app/guides/production-checklist'], tags: ['expansion-performance-diagnosis', 'profiling', 'optimization'] },
  { id: 'expansion-authorize-at-data-boundary', topicId: 'expansion-authorization-boundaries', topicFamily: 'production', title: 'Authorize at the Protected Data Boundary', summary: 'Use trusted server identity and resource ownership or permission checks where protected data is read or changed.', rationale: 'Client visibility and route redirects can be bypassed. The data operation needs a policy that remains true for direct requests and every caller.', tradeOffs: 'The policy must be applied consistently across reads and writes, which adds tests and server code.', appliesWhen: 'A route, action, or handler accesses user- or role-scoped data.', doesNotApplyWhen: 'The resource and operation are genuinely public.', example: 'Query a project by both projectId and session.user.id, then test a caller attempting to edit another owner’s project.', sourceLink: 'https://cheatsheetseries.owasp.org/cheatsheets/Authorization_Cheat_Sheet.html', sourceLinks: ['https://nextjs.org/docs/app/guides/authentication'], tags: ['expansion-authorization-boundaries', 'authorization', 'security'] },
  { id: 'expansion-type-boundaries-before-assertions', topicId: 'expansion-typescript-react-boundaries', topicFamily: 'foundations', title: 'Narrow External Data Before Assertions', summary: 'Treat browser, storage, and network values as unknown until runtime checks prove the shape required by the next layer.', rationale: 'Type assertions change the compiler’s view without changing the value. Narrowing or parsing keeps invalid data on an explicit recovery path.', tradeOffs: 'Boundary checks add code and may duplicate server schemas. That cost belongs at trust boundaries; internal values can rely more on inferred types.', appliesWhen: 'Data crosses from JSON, FormData, localStorage, URL input, or another untyped runtime boundary.', doesNotApplyWhen: 'The value was already constructed and validated inside the same typed module.', example: 'Parse an API response as unknown, validate its id and name, then pass Project props to a React component.', sourceLink: 'https://www.typescriptlang.org/docs/handbook/2/narrowing.html', sourceLinks: ['https://react.dev/learn/typescript'], tags: ['expansion-typescript-react-boundaries', 'typescript', 'runtime-validation'] },
  { id: 'expansion-test-visible-behavior', topicId: 'expansion-testing-user-behavior', topicFamily: 'app-quality', title: 'Test Observable Behavior', summary: 'Interact through the public UI and assert on what a user can perceive instead of private component state.', rationale: 'Behavior-focused tests survive refactors and catch regressions in labels, keyboard access, loading, errors, and success states.', tradeOffs: 'A public query can require more setup than reading a state variable. That setup is the contract being protected.', appliesWhen: 'Testing a React component or user-facing flow.', doesNotApplyWhen: 'The target is pure domain logic with no rendered behavior; test that logic directly.', example: 'Click the Save button by role and name, then assert the status region announces success or a recoverable error.', sourceLink: 'https://testing-library.com/docs/react-testing-library/intro/', sourceLinks: ['https://testing-library.com/docs/queries/about/'], tags: ['expansion-testing-user-behavior', 'testing-library', 'behavior'] },
  { id: 'expansion-release-from-evidence', topicId: 'expansion-production-readiness', topicFamily: 'production', title: 'Release from Production Evidence', summary: 'Require a production-like build, configuration check, critical smoke flow, failure signal, and rollback path before shipping.', rationale: 'Local development proves only one runtime mode. Release evidence must cover the built artifact and the operational boundaries that can fail after deployment.', tradeOffs: 'A release checklist adds deliberate coordination. It prevents teams from discovering configuration, caching, or rollback gaps during an incident.', appliesWhen: 'A feature changes production routes, data, configuration, or runtime behavior.', doesNotApplyWhen: 'A local-only experiment has no deployment or user data impact.', example: 'Build, smoke the protected route and error path, verify required server variables, inspect logs, and record the rollback trigger.', sourceLink: 'https://nextjs.org/docs/app/guides/production-checklist', sourceLinks: ['https://nextjs.org/docs/app/guides/self-hosting'], tags: ['expansion-production-readiness', 'deployment', 'operations'] },
  { id: 'expansion-record-tool-ownership', topicId: 'expansion-ecosystem-comparisons', topicFamily: 'architecture', title: 'Record Tool Ownership Before Adding Libraries', summary: 'Name the state or route owner and rejected alternatives before adding another ecosystem tool.', rationale: 'Explicit ownership prevents duplicate stores, competing routers, and synchronization code that exists only because a library was added without a distinct requirement.', tradeOffs: 'Writing a short decision record slows the first implementation. It makes later migration safer and gives the team a concrete trigger for revisiting the choice.', appliesWhen: 'A feature proposal introduces a new state, data, routing, or framework library.', doesNotApplyWhen: 'The tool is an internal implementation detail with no competing ownership or user-visible contract.', example: 'Keep a shareable filter in Next URL search params; add a client store only for a separate shared client-state requirement.', sourceLink: 'https://nextjs.org/docs/app', sourceLinks: ['https://redux-toolkit.js.org/introduction/getting-started', 'https://reactrouter.com/home'], tags: ['expansion-ecosystem-comparisons', 'architecture', 'tooling'] },
  { id: 'expansion-reconcile-optimistic-state', topicId: 'expansion-optimistic-mutations', topicFamily: 'nextjs-data', title: 'Reconcile Optimistic State with Server Truth', summary: 'Use optimistic UI for pending feedback, then replace or remove the projection according to the authoritative mutation result.', rationale: 'Optimistic state improves perceived latency but can be wrong. A visible pending state and explicit rejection path prevent stale or unauthorized projections from becoming misleading product state.', tradeOffs: 'Rollback and reconciliation add state transitions and failure UI. That cost is justified only when latency materially affects the interaction.', appliesWhen: 'A mutation is user-visible, latency-sensitive, and has a clear temporary projection.', doesNotApplyWhen: 'The operation is destructive, ambiguous, or too costly to represent safely before confirmation.', example: 'Show a pending note with a temporary id, replace it with the server-generated record on success, and remove it with a retry action on rejection.', sourceLink: 'https://react.dev/reference/react/useOptimistic', sourceLinks: ['https://react.dev/reference/react-dom/hooks/useFormStatus'], tags: ['expansion-optimistic-mutations', 'optimistic-ui', 'rollback', 'recovery'] },
  { id: 'expansion-route-failure-boundaries', topicId: 'app-router-and-layouts', topicFamily: 'nextjs-foundations', title: 'Assign Each Route Failure to Its Owning Boundary', summary: 'Use notFound, explicit expected-error UI, error.tsx/reset, and loading or Suspense according to the state each boundary owns.', rationale: 'Failure boundaries are not interchangeable. A precise mapping keeps expected user-correctable errors visible while preserving recovery for uncaught render failures and slow nested work.', tradeOffs: 'More boundaries require deliberate placement and smoke coverage, but a single global fallback hides ownership and recovery behavior.', appliesWhen: 'A route has missing resources, mutations, uncaught rendering risk, or independently slow dependencies.', doesNotApplyWhen: 'The state is pure domain logic with no route or rendering boundary.', example: 'Map a missing booking to notFound, a rejected form to returned field errors, an uncaught render error to error.tsx with reset, and a slow review panel to nested Suspense.', sourceLink: 'https://nextjs.org/docs/15/app/getting-started/error-handling', sourceLinks: ['https://nextjs.org/docs/15/app/getting-started/fetching-data'], tags: ['expansion-route-recovery', 'route-recovery', 'streaming', 'error-boundary'] },
  { id: 'expansion-triage-from-safe-signals', topicId: 'expansion-instrumentation-incident-triage', topicFamily: 'production', title: 'Triage from Safe Production Signals', summary: 'Connect impact, route and deployment context, a safe correlation id, error evidence, mitigation, verification, and rollback without logging secrets by default.', rationale: 'Instrumentation is useful only when its signal supports a bounded operational decision. Safe fields protect users while keeping the incident explainable.', tradeOffs: 'Redacting and structuring telemetry takes discipline and can reduce raw debugging detail. The trade-off protects credentials and personal data from becoming incident multipliers.', appliesWhen: 'A deployed route, Server Action, or background operation needs diagnosis.', doesNotApplyWhen: 'A local pure function can be diagnosed deterministically without runtime telemetry.', example: 'Record route, deployment, correlation id, error class, and timing; reproduce safely, apply the smallest mitigation, verify the smoke flow, and roll back on the agreed impact threshold.', sourceLink: 'https://nextjs.org/docs/15/app/guides/instrumentation', sourceLinks: ['https://nextjs.org/docs/15/app/guides/open-telemetry', 'https://nextjs.org/docs/15/app/guides/production-checklist'], tags: ['instrumentation', 'incident-response', 'observability', 'rollback'] },
];
